// 1. GET DATA
const aiItems = $input.all();
const formJson = $('SETUP FORM').first().json;
const primaryColor = formJson.PRIMARY_COLOR || "#3B82F6"; // Uses Form Color or defaults to Blue

let cleanerItems = [];
try { cleanerItems = $('Cleaner').all(); } catch (e) { cleanerItems = []; }

const results = [];
const DEFAULT_BG = "https://images.unsplash.com/photo-1620712943543-bcc4688e7485?q=80&w=1080&auto=format&fit=crop";

// Get Today's Date
const dateOptions = { month: 'short', day: 'numeric', year: 'numeric' };
const today = new Date().toLocaleDateString('en-US', dateOptions).toUpperCase().replace(',', ' •');

for (let i = 0; i < aiItems.length; i++) {
  const item = aiItems[i];

  // --- 2. RESTORE DATA ---
  let bgImage = DEFAULT_BG;
  let fallbackTitle = "Breaking News";

  if (cleanerItems.length > i) {
    if (cleanerItems[i].json.scraped_image) bgImage = cleanerItems[i].json.scraped_image;
    if (cleanerItems[i].json.title) fallbackTitle = cleanerItems[i].json.title;
  }

  // --- 3. PARSE AI RESPONSE ---
  let aiData = {};
  let rawText = "";
  if (item.json.output && item.json.output[0]?.content && item.json.output[0].content[0]?.text) {
    rawText = item.json.output[0].content[0].text;
  } else if (typeof item.json.output === 'string') rawText = item.json.output;
  else if (item.json.text) rawText = item.json.text;

  try {
    const cleanText = rawText.replace(/```json/g, "").replace(/```/g, "").trim();
    const firstBracket = cleanText.indexOf('{');
    const lastBracket = cleanText.lastIndexOf('}');
    if (firstBracket !== -1) aiData = JSON.parse(cleanText.substring(firstBracket, lastBracket + 1));
    else throw new Error("No JSON");
  } catch (error) {
    aiData = { headline: fallbackTitle, category: "NEWS UPDATE", caption: "Link in bio." };
  }

  const headline = (aiData.headline || fallbackTitle).replace(/"/g, '"');
  const category = (aiData.category || "TECHNOLOGY").toUpperCase();
  const caption = (aiData.caption || "").replace(/"/g, '"');

  // --- 4. HTML LAYOUT (With Dynamic Color) ---
  const htmlContent = `
  <!DOCTYPE html>
  <html>
  <head>
    <style>
      body { 
        margin: 0; padding: 0; 
        width: 1080px; height: 1350px; 
        background: linear-gradient(rgba(0,0,0,0.85), rgba(0,0,0,0.9)), url('${bgImage}');
        background-size: cover; background-position: center;
        font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif; 
        color: white; 
        display: flex; flex-direction: column; 
        justify-content: space-between; 
        align-items: center; text-align: center; 
        box-sizing: border-box;
      }
      .top-bar {
        width: 100%; padding-top: 60px;
        display: flex; justify-content: center;
      }
      .date-badge {
        font-size: 28px; font-weight: 700; letter-spacing: 3px; 
        color: rgba(255,255,255,0.6); text-transform: uppercase;
        border: 2px solid rgba(255,255,255,0.3);
        padding: 10px 30px; border-radius: 50px;
      }
      .container { 
        padding: 80px; display: flex; flex-direction: column; align-items: center; 
        margin-bottom: 100px;
      }
      .category-text {
        font-size: 34px; font-weight: 800; letter-spacing: 8px; 
        color: ${primaryColor}; /* DYNAMIC COLOR HERE */
        text-transform: uppercase;
        margin-bottom: 30px;
      }
      .headline { 
        font-size: 95px; line-height: 1.05; font-weight: 900; 
        margin-bottom: 60px; text-shadow: 0px 4px 10px rgba(0,0,0,0.8);
      }
      .caption {
        font-size: 42px; line-height: 1.5; font-weight: 400; color: #e0e0e0;
        max-width: 950px; 
        border-left: 8px solid ${primaryColor}; /* DYNAMIC COLOR HERE */
        padding-left: 40px; text-align: left;
      }
      .footer { 
        padding-bottom: 50px; font-size: 28px; opacity: 0.5; letter-spacing: 4px; font-weight: 600;
      }
    </style>
  </head>
  <body>
    <div class="top-bar">
      <div class="date-badge">${today}</div>
    </div>
    <div class="container">
      <div class="category-text">${category}</div>
      <div class="headline">${headline}</div>
      <div class="caption">${caption}</div>
    </div>
    <div class="footer">${formJson.BRAND_NAME}</div>
  </body>
  </html>
  `;

  const binaryData = await this.helpers.prepareBinaryData(Buffer.from(htmlContent), 'index.html', 'text/html');

  results.push({
    json: { 
      ...item.json, 
      headline, category, caption, 
      image_url: bgImage
    },
    binary: { index_html: binaryData }
  });
}

return results;

