// Get data from the RSS feed (Source) and the Scraper (Current Input)
const rssItems = $('News Source').all(); 
const scrapedItems = $input.all();
const results = [];

// Default image if none found
const DEFAULT_BG = "https://images.unsplash.com/photo-1620712943543-bcc4688e7485?q=80&w=1080&auto=format&fit=crop";

for (let i = 0; i < scrapedItems.length; i++) {
  const html = scrapedItems[i].json.data || "";
  let bgImage = DEFAULT_BG;

  // 1. EXTRACT IMAGE FROM HTML (Lightweight Regex)
  try {
    const match = html.match(/<meta property="og:image" content="([^"]+)"/);
    if (match && match[1]) {
      bgImage = match[1];
    }
  } catch (e) {}

  // 2. MERGE DATA
  // We take the clean text from RSS and combine it with our new image
  // We DO NOT pass the 'html' forward, saving thousands of tokens.
  if (rssItems[i]) {
    results.push({
      json: {
        title: rssItems[i].json.title,
        content: rssItems[i].json.contentSnippet || rssItems[i].json.content, // Use text only
        link: rssItems[i].json.link,
        scraped_image: bgImage
      }
    });
  }
}

return results;

// 1. Fetch IDs from the Facebook node to link the carousel
const containerItems = $('Create Container').all();
const mediaIds = containerItems.map(item => item.json.id).slice(0, 10);

// 2. Fetch the Headlines from the AI node for the caption list
const aiItems = $('AI Analyst').all();
const headlineList = aiItems
  .map(item => {
    let headline = "News Update";

    // Extracting headline from the AI JSON output
    try {
      let rawText = "";
      if (item.json.output && item.json.output[0]?.content) {
        rawText = item.json.output[0].content[0].text;
      } else if (typeof item.json.output === 'string') {
        rawText = item.json.output;
      }

      const cleanText = rawText.replace(/```json/g, "").replace(/```/g, "").trim();
      const data = JSON.parse(cleanText);
      headline = data.headline;
    } catch (e) {
      // Fallback to original RSS title if parsing fails
      headline = item.json.title || "Breaking News";
    }

    return `▪️ ${headline}`;
  })
  .slice(0, 10) // Ensure we only list the 10 slides
  .join('\n');

// 3. Format Today's Date (e.g., "DEC 30")
const dateOptions = { month: 'short', day: 'numeric' };
const today = new Date().toLocaleDateString('en-US', dateOptions).toUpperCase();

// 4. Build the final professional caption
const finalCaption = `⚡ DAILY TECH BRIEF • ${today}

${headlineList}

🔗 Link in Bio for full stories.

#TECH #AI #TechNews #Pixril`;

return {
  json: {
    children_string: mediaIds.join(','),
    caption: finalCaption
  }
};

