:root {
  /* --- CYBERPUNK THEME --- */
  --font-family: 'Inter', -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;

  /* Colors */
  --color-background: #0f111a; /* Dark Navy Background */
  --color-card-bg: #1e2130;    /* Lighter Navy Card */
  --color-card-border: #2d3248;
  --color-card-shadow: rgba(0, 0, 0, 0.4);

  --color-header: #ffffff;
  --color-header-subtext: #a0aec0;
  --color-label: #cbd5e0;

  /* Input Fields */
  --color-input-bg: #151823;
  --color-input-border: #2d3248;
  --color-input-text: #ffffff;
  --color-focus-border: #3B82F6; /* Bright Blue Focus */

  /* Buttons */
  --color-submit-btn-bg: #3B82F6;
  --color-submit-btn-text: #ffffff;
  --color-submit-btn-hover: #2563EB;

  /* Dimensions & Spacing */
  --border-radius-card: 12px;
  --border-radius-input: 8px;
  --container-width: 500px;
  --submit-btn-height: 52px;
}

/* Body Background */
body {
  background-color: var(--color-background) !important;
  color: var(--color-input-text);
}

/* Card Styling */
.n8n-form-container {
  box-shadow: 0 10px 40px -10px rgba(0,0,0,0.5);
  border: 1px solid var(--color-card-border);
}

/* Header Typography */
h1 {
  font-weight: 800 !important;
  letter-spacing: -0.5px;
  background: linear-gradient(to right, #fff, #a0aec0);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
}

/* Input Styling */
input, select, textarea {
  background-color: var(--color-input-bg) !important;
  border-color: var(--color-input-border) !important;
  color: white !important;
  transition: all 0.2s ease;
}

input:focus, select:focus {
  border-color: var(--color-focus-border) !important;
  box-shadow: 0 0 0 3px rgba(59, 130, 246, 0.2);
}

/* Button Styling */
button[type="submit"] {
  background: linear-gradient(135deg, #3B82F6 0%, #2563EB 100%);
  font-weight: 600;
  letter-spacing: 0.5px;
  text-transform: uppercase;
  font-size: 14px;
  transition: transform 0.1s;
}

button[type="submit"]:hover {
  transform: translateY(-1px);
  box-shadow: 0 4px 12px rgba(37, 99, 235, 0.3);
}
